async def get_or_create_entity(
    db: AsyncSession,
    *,
    entity_type: str,
    primary_image_url: str | None = None,
) -> int:
    sql = text("""
        INSERT INTO entity (entity_type, status, primary_image_url, external_ids, extra_metadata)
        VALUES (CAST(:etype AS entity_type), 'published', :img, '{}'::jsonb, '{}'::jsonb)
        RETURNING id
    """)
    return (await db.execute(sql, {"etype": entity_type, "img": primary_image_url})).scalar_one()


async def update_titles(db: AsyncSession) -> int:
    """Обновляет заголовки уже существующих статей."""
    updated = 0
    for upd in TITLE_UPDATES:
        result = await db.execute(text("""
            UPDATE entity_translation
            SET title = :title
            WHERE slug = :slug
              AND language_id = (SELECT id FROM language WHERE code = 'ru')
        """), {"title": upd["title"], "slug": upd["slug"]})
        if result.rowcount > 0:
            updated += 1
            log.info("✏️  Обновлён заголовок: %s", upd["title"])
    return updated


async def remove_old_sex_article(db: AsyncSession) -> None:
    """Удаляет старую версию «Секс в большом городе»."""
    old_slug = ARTICLE_SEX_REWRITE["old_slug"]
    # Находим entity_id
    row = (await db.execute(text("""
        SELECT entity_id FROM entity_translation
        WHERE slug = :slug
          AND language_id = (SELECT id FROM language WHERE code = 'ru')
    """), {"slug": old_slug})).first()
    if not row:
        log.info("Старая версия СВБГ (%s) не найдена — пропускаю удаление", old_slug)
        return
    entity_id = row[0]
    # Удаляем CASCADE через entity
    await db.execute(text("DELETE FROM entity WHERE id = :id"), {"id": entity_id})
    log.info("🗑️  Удалена старая версия СВБГ (entity_id=%d)", entity_id)


async def seed_article(db: AsyncSession, conf: dict) -> int | None:
    """Создаёт статью. Идемпотентно."""
    log.info("📝 %s", conf["title"])

    # Проверка существования по slug
    existing_sql = text("""
        SELECT et.entity_id FROM entity_translation et
        JOIN entity e ON e.id = et.entity_id
        WHERE e.entity_type = 'article'
          AND et.slug = :slug
          AND et.language_id = (SELECT id FROM language WHERE code = 'ru')
        LIMIT 1
    """)
    existing_id = (await db.execute(existing_sql, {"slug": conf["slug"]})).scalar_one_or_none()
    if existing_id:
        log.info("    уже существует (id=%d), пропускаю", existing_id)
        return existing_id

    article_entity_id = await get_or_create_entity(
        db, entity_type="article", primary_image_url=None,
    )

    await db.execute(text("""
        INSERT INTO article (id, article_type, author_user_id, reading_time_min, is_featured, extra_metadata)
        VALUES (:id, :atype, :auid, :rtime, :feat, '{}'::jsonb)
    """), {
        "id": article_entity_id,
        "atype": conf["article_type"],
        "auid": EDITORIAL_USER_ID,
        "rtime": conf.get("reading_time"),
        "feat": conf.get("is_featured", False),
    })

    await db.execute(text("UPDATE entity SET published_at = now() WHERE id = :id"),
                     {"id": article_entity_id})

    await db.execute(text("""
        INSERT INTO entity_translation (entity_id, language_id, search_config, slug, title, summary, description, body)
        VALUES (
            :id,
            (SELECT id FROM language WHERE code = 'ru'),
            'russian',
            :slug, :title, :summary, :summary, :body
        )
    """), {
        "id": article_entity_id,
        "slug": conf["slug"],
        "title": conf["title"],
        "summary": conf["summary"],
        "body": conf["body"],
    })

    await db.commit()
    log.info("    создана: id=%d (%d слов)", article_entity_id, len(conf["body"].split()))
    return article_entity_id


async def main() -> None:
    log.info("═════════════════════════════════════════════════")
    log.info("  Seed Articles v3 — обновления + 6 новых эссе")
    log.info("═════════════════════════════════════════════════")

    async with AsyncSessionLocal() as db:
        # 1) Обновить заголовки
        log.info("")
        log.info("─── Обновление заголовков ───")
        upd_count = await update_titles(db)
        await db.commit()
        log.info("    обновлено: %d", upd_count)

        # 2) Удалить старую СВБГ
        log.info("")
        log.info("─── Удаление старой версии СВБГ ───")
        await remove_old_sex_article(db)
        await db.commit()

        # 3) Создать новую СВБГ
        log.info("")
        log.info("─── Новая статья СВБГ ───")
        try:
            await seed_article(db, ARTICLE_SEX_REWRITE)
        except Exception as exc:
            log.error("ОШИБКА: %s", exc)
            await db.rollback()

        # 4) Создать остальные 5 новых
        log.info("")
        log.info("─── 5 новых статей ───")
        created = 0
        for a in NEW_ARTICLES:
            try:
                aid = await seed_article(db, a)
                if aid:
                    created += 1
            except Exception as exc:
                log.error("ОШИБКА: %s", exc)
                await db.rollback()

        log.info("")
        log.info("✅ Готово")
        log.info("    обновлены заголовки: %d", upd_count)
        log.info("    новых статей создано: %d", created + 1)

        total = (await db.execute(text("SELECT count(*) FROM article"))).scalar_one()
        log.info("    всего статей в БД: %d", total)


if __name__ == "__main__":
    asyncio.run(main())
